function asArray(value) {
  if (!value) return [];
  return Array.isArray(value) ? value : [value];
}
function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null) return value;
  }
  return null;
}
function compactMessages(messages) {
  return asArray(messages).slice(-10).map(m => ({
    sender: String(m.sender ?? ''),
    message_text: String(m.message_text ?? m.text ?? ''),
    message_type: String(m.message_type ?? 'text'),
    created_at: m.created_at ?? null
  }));
}
function hasLettersOrNumbers(text) {
  return /[\p{L}\p{N}]/u.test(text || '');
}
const raw = $json || {};
const messageValue = pick(raw.message_text, raw.raw_message_text, raw.input?.message_text, raw.chatInput, '');
const message_text = String(messageValue ?? '');
const media = raw.media || {};
const incomingAttachmentsSummary = raw.attachments_summary || raw.attachmentsSummary || {
  has_attachments: Boolean(media.has_attachments) || asArray(raw.attachments).length > 0,
  attachment_count: Number(media.attachment_count ?? asArray(raw.attachments).length ?? 0),
  attachment_kinds: asArray(media.attachment_kinds ?? media.kinds ?? [])
};
const attachments_summary = {
  has_attachments: Boolean(incomingAttachmentsSummary.has_attachments),
  attachment_count: Number(incomingAttachmentsSummary.attachment_count ?? 0),
  attachment_kinds: asArray(incomingAttachmentsSummary.attachment_kinds).map(String)
};
const memorySource = raw.conversation_memory || raw.memory || {};
const recentMessages = compactMessages(memorySource.last_messages || raw.last_messages || []);
const trimmed = message_text.trim();
const local_empty_text = trimmed.length === 0;
const local_noise_only = !attachments_summary.has_attachments && trimmed.length > 0 && !hasLettersOrNumbers(trimmed);
const local_attachment_only = attachments_summary.has_attachments && trimmed.length === 0;
return [{
  json: {
    message_text,
    channel: String(raw.channel ?? ''),
    attachments_summary,
    conversation_memory: {
      last_messages: recentMessages
    },
    metadata: {
      conversation_session_id: raw.metadata?.conversation_session_id ?? raw.conversation_session_id ?? null,
      workspace_id: raw.metadata?.workspace_id ?? raw.workspace_id ?? null,
      user_id: raw.metadata?.user_id ?? raw.user_id ?? null,
      project_id: raw.metadata?.project_id ?? raw.project_id ?? null
    },
    local_input_check: {
      empty_text: local_empty_text,
      noise_only: local_noise_only,
      attachment_only: local_attachment_only,
      has_letters_or_numbers: hasLettersOrNumbers(trimmed),
      should_treat_as_empty_or_noise_if_no_ai: !local_attachment_only && (local_empty_text || local_noise_only)
    }
  }
}];

const prepared = {
  raw_message_text: $json.message_text,
  attachments_summary: $json.attachments_summary,
  recent_conversation_messages: $json.conversation_memory?.last_messages || [],
  local_input_check: $json.local_input_check
};
return [{ json: { ...$json, openai_input: prepared } }];

function originalInput() {
  try {
    return $('Validate Input Shape').first().json;
  } catch (e) {
    return {};
  }
}

function extractText(obj) {
  if (typeof obj === 'string') return obj;

  if (Array.isArray(obj?.output)) {
    const first = obj.output[0];

    if (typeof first === 'string') return first;

    if (typeof first?.content === 'string') return first.content;

    if (Array.isArray(first?.content)) {
      const c0 = first.content[0];

      if (typeof c0 === 'string') return c0;
      if (typeof c0?.text === 'string') return c0.text;
      if (typeof c0?.text?.message === 'string') return c0.text.message;
      if (typeof c0?.message === 'string') return c0.message;
    }

    if (typeof first?.text === 'string') return first.text;
    if (typeof first?.message === 'string') return first.message;
    if (typeof first?.message?.content === 'string') return first.message.content;
  }

  if (typeof obj?.output === 'string') return obj.output;
  if (typeof obj?.text === 'string') return obj.text;
  if (typeof obj?.content === 'string') return obj.content;
  if (typeof obj?.message?.content === 'string') return obj.message.content;
  if (typeof obj?.choices?.[0]?.message?.content === 'string') return obj.choices[0].message.content;
  if (typeof obj?.data?.choices?.[0]?.message?.content === 'string') return obj.data.choices[0].message.content;
  if (typeof obj?.response?.body?.choices?.[0]?.message?.content === 'string') return obj.response.body.choices[0].message.content;

  return JSON.stringify(obj);
}

function parseJsonLoose(value) {
  if (!value) return null;

  if (typeof value === 'object' && !Array.isArray(value)) return value;

  const text = String(value);

  try {
    return JSON.parse(text);
  } catch (e) {}

  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) {
    try {
      return JSON.parse(fenced[1]);
    } catch (e) {}
  }

  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');

  if (start >= 0 && end > start) {
    try {
      return JSON.parse(text.slice(start, end + 1));
    } catch (e) {}
  }

  return null;
}

function hasLettersOrNumbers(text) {
  return /[\p{L}\p{N}]/u.test(text || '');
}

function detectLocalLanguage(text) {
  const raw = String(text || '');
  const arabicMatches = raw.match(/[\u0600-\u06FF]/g) || [];
  const englishMatches = raw.match(/[A-Za-z]/g) || [];

  const ar = arabicMatches.length;
  const en = englishMatches.length;

  if (ar > 0 && en > 0) return 'mixed';
  if (ar > 0 && en === 0) return 'ar-EG';
  if (en > 0 && ar === 0) return 'en';

  return 'other';
}

function fallbackResult(base, status, error, summaryOverride = null) {
  const local = base.local_input_check || {};
  const attachments = base.attachments_summary || {};
  const rawInput = String(base.message_text ?? '');

  const localLanguage = detectLocalLanguage(rawInput);

  const attachmentOnly = Boolean(
    local.attachment_only ||
    (attachments.has_attachments && rawInput.trim() === '')
  );

  const emptyOrNoise = attachmentOnly
    ? false
    : Boolean(
        local.should_treat_as_empty_or_noise_if_no_ai ||
        rawInput.trim() === '' ||
        !hasLettersOrNumbers(rawInput.trim())
      );

  let normalized = '';
  let summary = summaryOverride || 'Input normalization failed.';

  if (attachmentOnly) {
    const kinds =
      Array.isArray(attachments.attachment_kinds) && attachments.attachment_kinds.length
        ? attachments.attachment_kinds.join(', ')
        : 'media';

    normalized = `The user sent ${kinds} attachment(s) without accompanying text.`;
    summary = `User sent ${kinds} attachment(s) without text.`;
  } else if (rawInput.trim() === '') {
    summary = 'Empty user message.';
  } else if (emptyOrNoise) {
    summary = 'Noise-only message with no clear user request.';
  }

  return {
    detected_language: localLanguage,
    reply_language: localLanguage,
    raw_input: rawInput,
    normalized_english_input: status === 'failed' ? '' : normalized,
    message_summary_english: summary,
    is_empty_or_noise: emptyOrNoise,
    normalization_status: status,
    normalization_error: error
  };
}

function asBool(v) {
  return v === true || v === 'true';
}

const base = originalInput();
const rawText = extractText($json);
const parsed = parseJsonLoose(rawText);

if (!parsed || typeof parsed !== 'object') {
  return [
    {
      json: fallbackResult(base, 'failed', 'json_parse_failed')
    }
  ];
}

const allowedLanguages = new Set(['ar-EG', 'ar-Gulf', 'en', 'mixed', 'other']);
const allowedStatuses = new Set(['success', 'failed', 'fallback']);

const originalRaw = String(base.message_text ?? '');
const localLanguage = detectLocalLanguage(originalRaw);

let status = String(parsed.normalization_status ?? 'success');
let error = parsed.normalization_error ?? null;
let repaired = false;
let repairReasons = [];

let detected_language = String(parsed.detected_language ?? '').trim();

if (!allowedLanguages.has(detected_language)) {
  detected_language = localLanguage;
  repaired = true;
  repairReasons.push('invalid_detected_language');
}

let reply_language = String(parsed.reply_language ?? '').trim();

if (!allowedLanguages.has(reply_language)) {
  reply_language = detected_language;
  repaired = true;
  repairReasons.push('invalid_reply_language');
}

let raw_input = String(parsed.raw_input ?? '');

if (raw_input !== originalRaw) {
  raw_input = originalRaw;
  repaired = true;
  repairReasons.push('raw_input_mismatch_corrected');
}

let normalized_english_input = String(parsed.normalized_english_input ?? '');
let message_summary_english = String(parsed.message_summary_english ?? '');
let is_empty_or_noise = asBool(parsed.is_empty_or_noise);

if (!message_summary_english) {
  message_summary_english = originalRaw.trim()
    ? 'User message normalized for intake.'
    : 'Empty user message.';

  repaired = true;
  repairReasons.push('missing_message_summary_english');
}

if (!allowedStatuses.has(status)) {
  status = 'fallback';
  repaired = true;
  repairReasons.push('invalid_normalization_status');
}

if (repaired && status === 'success') status = 'fallback';
if (repaired && !error) error = repairReasons.join(',');

if (status === 'failed') {
  normalized_english_input = '';
  if (!error) error = 'normalization_failed';
}

return [
  {
    json: {
      detected_language,
      reply_language,
      raw_input,
      normalized_english_input,
      message_summary_english,
      is_empty_or_noise,
      normalization_status: status,
      normalization_error: error
    }
  }
];

const allowedKeys = [
  'detected_language',
  'reply_language',
  'raw_input',
  'normalized_english_input',
  'message_summary_english',
  'is_empty_or_noise',
  'normalization_status',
  'normalization_error'
];
const out = {};
for (const key of allowedKeys) out[key] = $json[key];
return [{ json: out }];
